create table dirkspzm32.lvs_check_log (
    sid              varchar2(2 char) not null enable,
    firma_nr         number(6, 0) not null enable,
    lvs_check_log_id number(*, 0) not null enable,
    login_id         number(*, 0),
    check_ts         date not null enable,
    arbeitsplatz_id  number(*, 0),
    check_typ        varchar2(20 char),
    scan_data_1      varchar2(255 char),
    scan_data_2      varchar2(255 char),
    soll_data_2      varchar2(255 char),
    check_q_eti_typ  varchar2(10 char),
    check_z_eti_typ  varchar2(10 char),
    check_passed     varchar2(1 char) default 'U' not null enable,
    lte_id           varchar2(20 char),
    lhm_id           varchar2(20 char),
    lgr_platz        varchar2(30 char)
);

alter table dirkspzm32.lvs_check_log
    add constraint pk_lvs_check_log
        primary key ( lvs_check_log_id,
                      firma_nr,
                      sid )
            using index enable;


